def test_duplicate_biller_registration_returns_409():
    headers = {"Authorization": f"Bearer {<valid_jwt_token>}"}
    payload = {
        "biller_name": "Existing Utility",
        "routing_number": "021000021",
        "account_number": "111111111"
    }
    <requests_post>("http://localhost/billers", json=payload, headers=headers)
    resp = <requests_post>("http://localhost/billers", json=payload, headers=headers)
    assert resp.status_code == 409
    data = resp.json()
    assert data["error_code"] == "BILLER_DUPLICATE"
    assert "error_message" in data
